import { invokeFunction, isArray } from '../../utils/zcutils';
import { isFunction } from '../../utils/function-utils';

export function parseRange() {
    let _scale = this,
        _config = _scale.config,
        _field = _config.field,
        _rangeConfig = _config.range;

    if (isArray(_rangeConfig)) {
        return _rangeConfig;
    }

    if (isFunction(_rangeConfig)) {
        invokeFunction(_rangeConfig, this);
        return;
    }
}
